import StoreAdBanner from "@/components/StoreAdBanner";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { MapPin, Phone, Mail, MessageCircle, Star, ChevronDown, ShoppingBag, Loader2, Camera, Ghost, Navigation, Pencil } from "lucide-react";
import { GhostRestaurantBrandStory } from "@/components/GhostRestaurantBrandStory";
import { BuildingStorySection } from "@/components/BuildingStorySection";
import { ChefRecommendedDishes } from "@/components/ChefRecommendedDishes";
import { InlinePhotoWallEditor } from "@/components/chef/InlinePhotoWallEditor";
import TranslatableText from "@/components/TranslatableText";

import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { getTypeDisplayLabel } from "@/hooks/useRestaurants";
import { RestaurantDishGallery } from "@/components/RestaurantDishGallery";
import { useDishImages } from "@/hooks/useDishImages";
import RestaurantRating from "@/components/RestaurantRating";
import { GhostRestaurantVideos } from "@/components/GhostRestaurantVideos";
import { lazy, Suspense, useRef } from "react";
import { getLocalizedBadgeText, getLocalizedActivityTitle, getLocalizedIntro } from "@/hooks/useRestaurantActivities";

const RestaurantComments = lazy(() => import("@/components/RestaurantComments"));

interface GhostRestaurantStoryProps {
  restaurant: any;
  localizedRestaurant: any;
  restaurantActivities: any[];
  ratingCount: number;
  averageRating: number;
  onTakeawayClick: () => void;
  onNavigationClick?: () => void;
  brandId?: string | null;
  /** Language code to auto-translate brand story, or null to show original */
  autoTranslateLang?: string | null;
  isEditMode?: boolean;
  canEdit?: boolean;
  draftRestaurant?: any;
  onDraftRestaurantChange?: (updates: Record<string, any>) => void;
}

export const GhostRestaurantStory = ({
  restaurant,
  localizedRestaurant,
  restaurantActivities,
  ratingCount,
  averageRating,
  onTakeawayClick,
  onNavigationClick,
  brandId,
  autoTranslateLang,
  isEditMode = false,
  canEdit = false,
  draftRestaurant,
  onDraftRestaurantChange,
}: GhostRestaurantStoryProps) => {
  const { t, i18n } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  // activitiesOpen state removed - activities now shown as standalone section
  const { data: dishImages = [] } = useDishImages(restaurant.id);
  const hasDishImages = dishImages.length > 0 && (restaurant as any).show_dish_gallery !== false;
  const isClaimed = restaurant.store_level && restaurant.store_level !== 'shell';
  
  const commentsSectionRef = useRef<HTMLDivElement>(null);

  return (
    <div className="relative bg-background">
      {/* Building Story Section - Core content, shown first */}
      <BuildingStorySection restaurant={restaurant} variant="section" />

      {/* Chef Recommended Dishes with Huangdi Neijing */}
      <ChefRecommendedDishes restaurantId={restaurant.id} isEditMode={isEditMode} canEdit={canEdit} />

      {/* Takeaway CTA Section */}
      {(restaurant as any).takeaway_url && (restaurant as any).show_takeaway_button && (
        <section className="py-6 md:py-8 bg-gradient-to-b from-muted/50 to-background">
          <div className="container mx-auto max-w-2xl px-4">
            <div className="text-center mb-4 md:mb-5">
              <p className="text-xs md:text-sm text-muted-foreground mb-1">
                {t("restaurants.readyToOrder")}
              </p>
              <p className="text-sm md:text-base font-medium text-foreground">
                {t("restaurants.orderNowHint")}
              </p>
            </div>
            <div className="max-w-md mx-auto">
              <Button 
                className="w-full h-11 md:h-12 text-sm md:text-base shadow-md hover:shadow-lg transition-shadow"
                size="lg"
                onClick={onTakeawayClick}
              >
                <ShoppingBag className="w-4 h-4 md:w-5 md:h-5 mr-2" />
                {t("restaurant.takeawayOrder")}
              </Button>
            </div>
            <div className="flex items-center justify-center gap-3 mt-4 md:mt-5">
              <div className="h-px w-12 md:w-16 bg-border" />
              <span className="text-[10px] md:text-xs text-muted-foreground uppercase tracking-wider">
                {t("restaurants.orBrowse")}
              </span>
              <div className="h-px w-12 md:w-16 bg-border" />
            </div>
          </div>
        </section>
      )}

      {/* Photo Gallery Section - only show if there are images or edit mode is active */}
      {(hasDishImages || (isEditMode && canEdit)) && (
        <section className="py-8 md:py-12 lg:py-16">
          <div className="container mx-auto max-w-6xl px-4">

            <div className="text-center mb-6 md:mb-8 lg:mb-10">
              <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
                {t("restaurants.gallery", "美食图鉴")}
              </p>
              <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground flex items-center justify-center gap-2 md:gap-3">
                <Camera className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary" />
                {t("restaurants.photoWall", "照片墙")}
              </h2>
              <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
            </div>
            
            {isEditMode && canEdit ? (
              <InlinePhotoWallEditor restaurantId={restaurant.id} />
            ) : (
              <RestaurantDishGallery restaurantId={restaurant.id} showGallery={(restaurant as any).show_dish_gallery !== false} />
            )}
          </div>
        </section>
      )}

      {/* Video Gallery Section - Behind The Kitchen */}
      {restaurant.videos && Array.isArray(restaurant.videos) && restaurant.videos.length > 0 && (
        <GhostRestaurantVideos videos={restaurant.videos} />
      )}

      {/* Brand Story Section */}
      {brandId && (
        <GhostRestaurantBrandStory brandId={brandId} autoTranslateLang={autoTranslateLang} />
      )}

      {/* Activities Section - Standalone above restaurant info */}
      {restaurantActivities.length > 0 && (
        <section className="py-8 md:py-12 lg:py-16">
          <div className="container mx-auto max-w-4xl px-4">
            <div className="text-center mb-6 md:mb-8 lg:mb-10">
              <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
                {t("restaurants.participating", "参与中")}
              </p>
              <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground flex items-center justify-center gap-2 md:gap-3">
                <Star className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary" />
                {t("activities.title")}
              </h2>
              <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
            </div>

            <div className="grid gap-3 md:gap-4">
              {restaurantActivities.map((activity, idx) => {
                const intro = getLocalizedIntro(activity, i18n.language);
                return (
                  <Link
                    key={`activity-card-${idx}`}
                    to={`/activity/${activity.activity_id}`}
                    className="block"
                  >
                    <Card className="border-0 shadow-md hover:shadow-lg transition-shadow overflow-hidden">
                      <CardContent className="p-4 md:p-5 flex items-center gap-3 md:gap-4">
                        <Badge 
                          variant="default" 
                          className="text-white text-xs md:text-sm shrink-0"
                          style={{ backgroundColor: activity.badge_color || "hsl(var(--primary))" }}
                        >
                          {getLocalizedBadgeText(activity, i18n.language)}
                        </Badge>
                        <div className="min-w-0 flex-1">
                          <p className="font-semibold text-sm md:text-base text-card-foreground truncate">
                            {getLocalizedActivityTitle(activity, i18n.language)}
                          </p>
                          {intro && (
                            <p className="text-xs md:text-sm text-muted-foreground line-clamp-1 mt-0.5">
                              {intro}
                            </p>
                          )}
                        </div>
                        <ChevronDown className="w-4 h-4 text-muted-foreground -rotate-90 shrink-0" />
                      </CardContent>
                    </Card>
                  </Link>
                );
              })}
            </div>
          </div>
        </section>
      )}

      {/* Info Section - Contact & Details */}
      <section className="py-8 md:py-12 lg:py-16 bg-muted/30">
        <div className="container mx-auto max-w-4xl px-4">
          <div className="text-center mb-6 md:mb-8 lg:mb-10">
            <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
              {t("restaurants.info", "详情")}
            </p>
            <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground flex items-center justify-center gap-2 md:gap-3">
              <MapPin className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary" />
              {t("restaurants.contactInfo", "联系信息")}
            </h2>
            <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
          </div>

          <Card className="border-0 shadow-lg md:shadow-xl overflow-hidden">
            <CardContent className="p-4 md:p-6 lg:p-8 space-y-4 md:space-y-6">
              {/* Type tags and rating */}
              <div className="flex flex-wrap items-center gap-2 md:gap-3">
                <Badge variant="secondary" className="gap-1 text-xs md:text-sm bg-primary/10 text-primary border-primary/20">
                  {(() => {
                    if (restaurant.template === 'michelin' || restaurant.michelin_stars) {
                      const michelinLabels: Record<string, Record<string, string>> = {
                        "3": { zh: "米其林三星", en: "Michelin Three Stars", pt: "Michelin Três Estrelas", ar: "ميشلان ثلاث نجوم", ja: "ミシュラン三つ星", ko: "미슐랭 쓰리스타", fr: "Trois Étoiles Michelin", de: "Drei Michelin Sterne", es: "Tres Estrellas Michelin", it: "Tre Stelle Michelin", ru: "Три звезды Мишлен" },
                        "2": { zh: "米其林二星", en: "Michelin Two Stars", pt: "Michelin Duas Estrelas", ar: "ميشلان نجمتان", ja: "ミシュラン二つ星", ko: "미슐랭 투스타", fr: "Deux Étoiles Michelin", de: "Zwei Michelin Sterne", es: "Dos Estrellas Michelin", it: "Due Stelle Michelin", ru: "Две звезды Мишлен" },
                        "1": { zh: "米其林一星", en: "Michelin One Star", pt: "Michelin Uma Estrela", ar: "ميشلان نجمة واحدة", ja: "ミシュラン一つ星", ko: "미슐랭 원스타", fr: "Une Étoile Michelin", de: "Ein Michelin Stern", es: "Una Estrella Michelin", it: "Una Stella Michelin", ru: "Одна звезда Мишлен" },
                        "bib_gourmand": { zh: "米其林必比登推介", en: "Michelin Bib Gourmand", pt: "Michelin Bib Gourmand", ar: "ميشلان بيب غورماند", ja: "ミシュラン ビブグルマン", ko: "미슐랭 빕 구르망", fr: "Michelin Bib Gourmand", de: "Michelin Bib Gourmand", es: "Michelin Bib Gourmand", it: "Michelin Bib Gourmand", ru: "Мишлен Биб Гурман" },
                        "selected": { zh: "米其林入选", en: "Michelin Selected", pt: "Michelin Selected", ar: "ميشلان مختار", ja: "ミシュランセレクション", ko: "미슐랭 셀렉션", fr: "Michelin Sélection", de: "Michelin Auswahl", es: "Michelin Selección", it: "Michelin Selected", ru: "Мишлен Выбор" },
                      };
                      const stars = (restaurant as any).michelin_stars;
                      const lang = i18n.language;
                      const entry = stars ? michelinLabels[stars] : null;
                      return entry ? (entry[lang] || entry.en) : t("admin.templateMichelin", "Michelin");
                    }
                    return t("admin.templateGhost", "Virtual Kitchen");
                  })()}
                  {!(restaurant.template === 'michelin' || restaurant.michelin_stars) && <Ghost className="w-3 h-3" />}
                </Badge>
                {(() => {
                  const rawTypes = localizedRestaurant.type || [];
                  const genericMichelinTags = new Set(["米其林", "Michelin"]);
                  const starDupTags = new Set(["一星", "二星", "三星", "必比登推介", "米其林入选",
                    "One Michelin Star", "Two Michelin Stars", "Three Michelin Stars",
                    "Uma Estrela Michelin", "Duas Estrelas Michelin", "Três Estrelas Michelin",
                    "Bib Gourmand", "Michelin Selected"]);
                  return rawTypes.slice(0, 3)
                    .filter((t: string) => !genericMichelinTags.has(t) && !starDupTags.has(t) && !/米其林.*星/.test(t))
                    .map((type: string, idx: number) => (
                      <Badge key={idx} variant="secondary" className="text-xs md:text-sm">{getTypeDisplayLabel(type, i18n.language)}</Badge>
                    ));
                })()}
                {ratingCount > 0 && (
                  <div className="flex items-center gap-1 ml-auto">
                    <Star className="w-4 h-4 md:w-5 md:h-5 fill-accent text-accent" />
                    <span className="font-bold text-base md:text-lg">
                      {averageRating.toFixed(1)}
                      <span className="text-muted-foreground font-normal text-xs md:text-sm ml-1">({ratingCount})</span>
                    </span>
                  </div>
                )}
              </div>

              <Separator />

              {/* Contact Info Grid */}
              <div className="grid gap-3 md:gap-4">
                {/* Kitchen Address */}
                <div className="flex items-start gap-2 md:gap-3 p-3 md:p-4 rounded-lg md:rounded-xl bg-muted/50 hover:bg-muted/70 transition-colors">
                  <MapPin className="w-4 h-4 md:w-5 md:h-5 text-primary mt-0.5 flex-shrink-0" />
                  <div className="min-w-0 flex-1">
                    <p className="font-semibold text-sm md:text-base text-card-foreground">{t("restaurants.kitchenAddress")}</p>
                    {isEditMode && canEdit && draftRestaurant && onDraftRestaurantChange ? (
                      <Input
                        value={draftRestaurant.address || ""}
                        onChange={(e) => onDraftRestaurantChange({ address: e.target.value })}
                        placeholder={t("restaurant.addressPlaceholder", "Enter restaurant address")}
                        className="mt-1"
                      />
                    ) : isClaimed && restaurant.address ? (
                      <TranslatableText text={restaurant.address} className="mt-0.5 md:mt-1" />
                    ) : (
                      <p className="text-xs md:text-sm text-muted-foreground mt-0.5 md:mt-1 break-words">{restaurant.address}</p>
                    )}
                  </div>
                </div>

                {/* Navigation Button */}
                {onNavigationClick && !isEditMode && (
                  <Button 
                    variant="secondary"
                    className="w-full"
                    onClick={onNavigationClick}
                  >
                    <Navigation className="w-4 h-4 mr-2" />
                    {t("restaurant.getDirections")}
                  </Button>
                )}

                {/* Phone */}
                <div className="flex items-start gap-2 md:gap-3 p-3 md:p-4 rounded-lg md:rounded-xl bg-muted/50 hover:bg-muted/70 transition-colors">
                  <Phone className={`w-4 h-4 md:w-5 md:h-5 ${(restaurant as any).store_level === 'shell' ? 'text-muted-foreground' : 'text-primary'} mt-0.5 flex-shrink-0`} />
                  <div className="min-w-0 flex-1">
                    <p className="font-semibold text-sm md:text-base text-card-foreground">{t("restaurant.phone")}</p>
                    {isEditMode && canEdit && draftRestaurant && onDraftRestaurantChange ? (
                      <Input
                        value={draftRestaurant.phone || ""}
                        onChange={(e) => onDraftRestaurantChange({ phone: e.target.value })}
                        placeholder={t("restaurant.phonePlaceholder", "Enter phone number")}
                        className="mt-1"
                      />
                    ) : (restaurant as any).store_level === 'shell' ? (
                      <p className="text-xs text-muted-foreground mt-0.5">{t("restaurants.phoneAfterClaim", "认领之后将会显示电话号码")}</p>
                    ) : restaurant.phone ? (
                      <a href={`tel:${restaurant.phone}`} className="text-sm md:text-base text-primary hover:underline mt-0.5 md:mt-1 block">{restaurant.phone}</a>
                    ) : (
                      <p className="text-xs text-muted-foreground mt-0.5">{t("common.notAvailable", "N/A")}</p>
                    )}
                  </div>
                </div>

                {/* Email */}
                <div className="flex items-start gap-2 md:gap-3 p-3 md:p-4 rounded-lg md:rounded-xl bg-muted/50 hover:bg-muted/70 transition-colors">
                  <Mail className="w-4 h-4 md:w-5 md:h-5 text-primary mt-0.5 flex-shrink-0" />
                  <div className="min-w-0 flex-1">
                    <p className="font-semibold text-sm md:text-base text-card-foreground">{t("restaurant.email", "Email")}</p>
                    {isEditMode && canEdit && draftRestaurant && onDraftRestaurantChange ? (
                      <Input
                        value={draftRestaurant.email || ""}
                        onChange={(e) => onDraftRestaurantChange({ email: e.target.value })}
                        placeholder={t("restaurant.emailPlaceholder", "Enter email address")}
                        className="mt-1"
                      />
                    ) : restaurant.email ? (
                      <a href={`mailto:${restaurant.email}`} className="text-sm md:text-base text-primary hover:underline mt-0.5 md:mt-1 block">{restaurant.email}</a>
                    ) : (
                      <p className="text-xs text-muted-foreground mt-0.5">{t("common.notAvailable", "N/A")}</p>
                    )}
                  </div>
                </div>

              </div>

              {isEditMode && canEdit && (
                <div className="rounded-2xl border-2 border-primary/20 bg-primary/5 p-3">
                  <p className="flex items-center gap-2 text-xs font-medium text-primary">
                    <Pencil className="h-3.5 w-3.5" />
                    {t("restaurant.editModeHint", "Edit mode: Click the \"Save\" button at the top to save all changes")}
                  </p>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </section>

      {/* Store Ad Banner - between info and rating, only for unclaimed stores */}
      <div className="max-w-4xl mx-auto px-4 md:px-8">
        <StoreAdBanner country={restaurant.country || null} city={restaurant.city || null} storeLevel={restaurant.store_level || 'shell'} adNameFilter="SaaS" />
      </div>

      {/* Rating Section */}
      <section className="py-8 md:py-12 lg:py-16">
        <div className="container mx-auto max-w-4xl px-4">
          <div className="text-center mb-6 md:mb-8 lg:mb-10">
            <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
              {t("restaurants.rating", "评分")}
            </p>
            <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground flex items-center justify-center gap-2 md:gap-3">
              <Star className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary" />
              {t("restaurants.rateUs", "给我们评分")}
            </h2>
            <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
          </div>

          <Card className="border-0 shadow-lg md:shadow-xl overflow-hidden">
            <CardContent className="p-4 md:p-6 lg:p-8">
              <RestaurantRating restaurantId={restaurant.id} />
            </CardContent>
          </Card>
        </div>
      </section>

      {/* Comments Section */}
      <section className="py-8 md:py-12 lg:py-16 bg-muted/30">
        <div className="container mx-auto max-w-4xl px-4">
          <div className="text-center mb-6 md:mb-8 lg:mb-10">
            <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
              {t("restaurants.reviews", "评价")}
            </p>
            <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground flex items-center justify-center gap-2 md:gap-3">
              <MessageCircle className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary" />
              {t("restaurants.customerReviews", "用户评价")}
            </h2>
            <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
          </div>

          <Card className="border-0 shadow-lg md:shadow-xl overflow-hidden">
            <CardContent className="p-4 md:p-6 lg:p-8" ref={commentsSectionRef}>
              <Suspense fallback={
                <div className="flex items-center justify-center py-8 md:py-12">
                  <Loader2 className="w-6 h-6 md:w-8 md:h-8 animate-spin text-primary" />
                </div>
              }>
                <RestaurantComments restaurantId={restaurant.id} />
              </Suspense>
            </CardContent>
          </Card>
        </div>
      </section>
    </div>
  );
};

export default GhostRestaurantStory;
